chordpro:
{title: Silent Night}
{subtitle: Stille Nacht — Mohr/Gruber (1818), English tr. John Freeman Young (1859)}
{key: C}
{time: 6/8}
{tempo: 76}
{comment: UNESCO declared this an Intangible Cultural Heritage in 2011.}

{start_of_verse: 1}
[C]Silent night, holy [G]night
[G]All is calm, all is [C]bright
[F]Round yon Virgin [C]Mother and Child
[F]Holy Infant so [C]tender and mild
[G]Sleep in heavenly [C]peace
[C]Sleep in heavenly [G]peace[C]
{end_of_verse}

{start_of_verse: 2}
[C]Silent night, holy [G]night
[G]Shepherds quake at the [C]sight
[F]Glories stream from [C]heaven afar
[F]Heavenly hosts sing [C]Alleluia!
[G]Christ the Saviour is [C]born
[C]Christ the Saviour is [G]born[C]
{end_of_verse}

{start_of_verse: 3}
[C]Silent night, holy [G]night
[G]Son of God, love's pure [C]light
[F]Radiant beams from [C]Thy holy face
[F]With the dawn of re[C]deeming grace
[G]Jesus, Lord, at Thy [C]birth
[C]Jesus, Lord, at Thy [G]birth[C]
{end_of_verse}
